module RefModule(
    input [2:0] in,     // 3-bit input.
    input en,           // Enable signal to activate the decoder.

    output [7:0] out    // 8-bit output.
);

reg [7:0] unused_out_r;

//------------------------------------------------
// 3-to-8 Decoder logic
always @(*) begin
    if (en) begin
        case (in)
            3'b000: unused_out_r = 8'b00000001;
            3'b001: unused_out_r = 8'b00000010;
            3'b010: unused_out_r = 8'b00000100;
            3'b011: unused_out_r = 8'b00001000;
            3'b100: unused_out_r = 8'b00010000;
            3'b101: unused_out_r = 8'b00100000;
            3'b110: unused_out_r = 8'b01000000;
            3'b111: unused_out_r = 8'b10000000;
            default: unused_out_r = 8'b00000000;
        endcase
    end else begin
        unused_out_r = 8'b00000000;
    end
end

assign out = unused_out_r;

endmodule
